import{_ as l,c as t,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.40：全局配置支持，快捷键改进","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.40.md","filePath":"changelog/v1.1.40.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.40.md"};function h(d,e,n,s,p,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-40-全局配置支持-快捷键改进" tabindex="-1">v1.1.40：全局配置支持，快捷键改进 <a class="header-anchor" href="#v1-1-40-全局配置支持-快捷键改进" aria-label="Permalink to “v1.1.40：全局配置支持，快捷键改进”">​</a></h1><p><strong>发布日期</strong>：2026年01月28日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新新增了全局配置支持，添加了 Thai 语言支持，并改进了快捷键导航。</p><hr><h2 id="新功能-全局配置支持" tabindex="-1">新功能：全局配置支持 <a class="header-anchor" href="#新功能-全局配置支持" aria-label="Permalink to “新功能：全局配置支持”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 Desktop 应用中新增了全局配置功能，可以设置跨项目的全局配置项。</p><h3 id="全局配置是什么" tabindex="-1">全局配置是什么？ <a class="header-anchor" href="#全局配置是什么" aria-label="Permalink to “全局配置是什么？”">​</a></h3><p>全局配置是独立于特定项目设置的配置，适用于所有项目。例如，你可以设置全局的模型选择、主题偏好等。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开设置</li><li>找到&quot;全局配置&quot;选项</li><li>设置适用于所有项目的配置项</li></ol><hr><h2 id="新功能-thai-语言支持" tabindex="-1">新功能：Thai 语言支持 <a class="header-anchor" href="#新功能-thai-语言支持" aria-label="Permalink to “新功能：Thai 语言支持”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增了泰国语（Thai）的界面翻译支持。</p><h3 id="如何切换语言" tabindex="-1">如何切换语言？ <a class="header-anchor" href="#如何切换语言" aria-label="Permalink to “如何切换语言？”">​</a></h3><p>在设置中选择 Thai 语言，界面将自动切换为泰语显示。</p><hr><h2 id="新功能-快捷键改进" tabindex="-1">新功能：快捷键改进 <a class="header-anchor" href="#新功能-快捷键改进" aria-label="Permalink to “新功能：快捷键改进”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 Desktop 应用中，现在可以使用 <code>Ctrl+N</code> 和 <code>Ctrl+P</code> 在弹出菜单中进行上下导航。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><ul><li><code>Ctrl+N</code>：向下导航到下一项</li><li><code>Ctrl+P</code>：向上导航到上一项</li></ul><p>这让你可以不使用鼠标快速浏览和选择菜单项。</p><hr><h2 id="新功能-自定义提供商支持" tabindex="-1">新功能：自定义提供商支持 <a class="header-anchor" href="#新功能-自定义提供商支持" aria-label="Permalink to “新功能：自定义提供商支持”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>Desktop 应用现在支持添加自定义的 AI 模型提供商。</p><h3 id="如何使用-2" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-2" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开设置</li><li>进入&quot;提供商&quot;配置</li><li>添加自定义提供商的 API 地址和认证信息</li></ol><hr><h2 id="新功能-subtaskpart" tabindex="-1">新功能：SubtaskPart <a class="header-anchor" href="#新功能-subtaskpart" aria-label="Permalink to “新功能：SubtaskPart”">​</a></h2><h3 id="这次更新了什么-4" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-4" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增了 SubtaskPart 组件，支持元数据引用，让任务分解更加结构化。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Desktop 版</td><td>✅ 推荐升级（新功能丰富）</td></tr><tr><td>需要统一配置</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',40),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add SubtaskPart with metadata reference (@YangTianz)</li><li>Add global configuration support to app</li><li>Global configuration updates in app package</li><li>Bump plugins</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add streaming prop to markdown element (@remorses)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Close review pane when pressing escape key</li><li>Enable ctrl+n and ctrl+p for popover navigation in desktop app (@sairajchouhan)</li><li>Add Thai locale support (@natt-v)</li><li>Add custom provider support to app</li></ul><p><strong>Thank you to 4 community contributors:</strong></p><p>@natt-v:</p><ul><li>feat(i18n): add th locale support (#10809)</li></ul><p>@sairajchouhan:</p><ul><li>fix(desktop): enable ctrl+n and ctrl+p for popover navigation (#10777)</li></ul><p>@YangTianz:</p><ul><li>fix: add SubtaskPart with metadata reference (#10990)</li></ul><p>@remorses:</p><ul><li>fix(markdown): Add streaming prop to markdown element (#11025)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=l(o,[["render",h]]);export{u as __pageData,m as default};
